"""Plot and analyze results generated by tests/run_bench_suite.py."""

from __future__ import annotations

import argparse
import json
from pathlib import Path
from typing import Any

import matplotlib.pyplot as plt


TASK_UPDATE_ONLY = "task_update_only"
TASK_UPDATE_WITH_OBS = "task_update_with_obs"
ENV_UPDATE_WITH_OBS = "env_update_with_obs"


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "suite_dir",
        nargs="?",
        default=None,
        help="Path to a benchmark suite directory. Defaults to the latest one under outputs/bench_suite.",
    )
    return parser.parse_args()


def main() -> int:
    args = parse_args()
    suite_dir = resolve_suite_dir(args.suite_dir)
    manifest = json.loads((suite_dir / "manifest.json").read_text())
    results = load_results(suite_dir / "results")

    task_only = collect_by_scenario(results, TASK_UPDATE_ONLY)
    task_obs = collect_by_scenario(results, TASK_UPDATE_WITH_OBS)
    env_obs = collect_by_scenario(results, ENV_UPDATE_WITH_OBS)

    if not task_only or not task_obs or not env_obs:
        raise ValueError(f"Incomplete results under {suite_dir}")

    plot_task_frequency(suite_dir, task_only, task_obs)
    plot_env_breakdown(suite_dir, env_obs)
    plot_gpu_memory(suite_dir, task_only)
    write_analysis(suite_dir, manifest, task_only, task_obs, env_obs)

    print(f"Plots and analysis saved to {suite_dir.resolve()}")
    return 0


def resolve_suite_dir(raw: str | None) -> Path:
    if raw is not None:
        suite_dir = Path(raw)
        if not (suite_dir / "manifest.json").exists():
            raise FileNotFoundError(f"manifest.json not found under {suite_dir}")
        return suite_dir

    root = Path("outputs/bench_suite")
    candidates = sorted(
        [path for path in root.iterdir() if (path / "manifest.json").exists()]
    )
    if not candidates:
        raise FileNotFoundError("No benchmark suite found under outputs/bench_suite")
    return candidates[-1]


def load_results(results_dir: Path) -> list[dict[str, Any]]:
    payloads = []
    for path in sorted(results_dir.glob("*.json")):
        payloads.append(json.loads(path.read_text()))
    return payloads


def collect_by_scenario(
    results: list[dict[str, Any]], scenario: str
) -> list[dict[str, Any]]:
    items = [item for item in results if item["scenario"] == scenario]
    return sorted(items, key=lambda item: item["batch_size"])


def plot_task_frequency(
    suite_dir: Path,
    task_only: list[dict[str, Any]],
    task_obs: list[dict[str, Any]],
) -> None:
    batch_sizes = [item["batch_size"] for item in task_only]
    only_hz = [item["loop_frequency_hz"] for item in task_only]
    obs_hz = [item["loop_frequency_hz"] for item in task_obs]

    plt.figure(figsize=(8, 5))
    plt.plot(batch_sizes, only_hz, marker="o", linewidth=2.2, label="task update")
    plt.plot(
        batch_sizes,
        obs_hz,
        marker="s",
        linewidth=2.2,
        label="task update + observation",
    )
    plt.xlabel("Batch size")
    plt.ylabel("Loop frequency (Hz)")
    plt.title("Task-Level Benchmark")
    plt.grid(alpha=0.3)
    plt.legend()
    plt.tight_layout()
    plt.savefig(suite_dir / "task_level_frequency.png", dpi=180)
    plt.close()


def plot_env_breakdown(suite_dir: Path, env_obs: list[dict[str, Any]]) -> None:
    batch_sizes = [item["batch_size"] for item in env_obs]
    capture_ms = [item["capture_observation_mean_ms"] for item in env_obs]
    update_ms = [item["update_mean_ms"] for item in env_obs]
    total_ms = [item["total_mean_ms"] for item in env_obs]

    plt.figure(figsize=(8, 5))
    plt.plot(batch_sizes, capture_ms, marker="o", linewidth=2.2, label="capture")
    plt.plot(batch_sizes, update_ms, marker="s", linewidth=2.2, label="update")
    plt.plot(batch_sizes, total_ms, marker="^", linewidth=2.2, label="total")
    plt.xlabel("Batch size")
    plt.ylabel("Mean latency (ms)")
    plt.title("Env-Level Benchmark Breakdown")
    plt.grid(alpha=0.3)
    plt.legend()
    plt.tight_layout()
    plt.savefig(suite_dir / "env_level_breakdown.png", dpi=180)
    plt.close()


def plot_gpu_memory(suite_dir: Path, task_only: list[dict[str, Any]]) -> None:
    batch_sizes = [item["batch_size"] for item in task_only]
    peaks = [
        float(item["gpu_memory_peak_mb"])
        if item["gpu_memory_peak_mb"] is not None
        else 0
        for item in task_only
    ]

    plt.figure(figsize=(8, 5))
    plt.plot(batch_sizes, peaks, marker="o", linewidth=2.2, color="#b85c38")
    plt.xlabel("Batch size")
    plt.ylabel("Peak GPU memory (MB)")
    plt.title("GPU Memory for Task Update")
    plt.grid(alpha=0.3)
    plt.tight_layout()
    plt.savefig(suite_dir / "task_level_gpu_memory.png", dpi=180)
    plt.close()


def write_analysis(
    suite_dir: Path,
    manifest: dict[str, Any],
    task_only: list[dict[str, Any]],
    task_obs: list[dict[str, Any]],
    env_obs: list[dict[str, Any]],
) -> None:
    lines: list[str] = []
    lines.append("# Benchmark Analysis")
    lines.append("")
    lines.append(f"- config_name: `{manifest['config_name']}`")
    lines.append(f"- batch_sizes: `{manifest['batch_sizes']}`")
    lines.append("")
    lines.append(
        "> 说明：task-level `loop_frequency_hz` 是整个 batch 的循环频率，"
        "不是单个 env 的观测延迟。"
    )
    lines.append(
        "> 对于这个 GS 任务，`batch_size=1` 和 `batch_size=2` 都走同一个 "
        "`BatchedGSUnifiedMujocoEnv` 观测实现；差别在于 batched renderer 的输入规模不同，"
        "因此 `batch_size=2` 的 batch loop Hz 高于 `batch_size=1` 仍然可能成立。"
    )
    lines.append("")

    lines.append("## Task-Level Batch Loop Frequency")
    for only_item, obs_item in zip(task_only, task_obs, strict=True):
        slowdown = percentage_delta(
            obs_item["loop_frequency_hz"], only_item["loop_frequency_hz"]
        )
        only_step_ms = (
            1000.0 / only_item["loop_frequency_hz"]
            if only_item["loop_frequency_hz"] > 0
            else 0.0
        )
        obs_step_ms = (
            1000.0 / obs_item["loop_frequency_hz"]
            if obs_item["loop_frequency_hz"] > 0
            else 0.0
        )
        lines.append(
            "- "
            f"batch_size={only_item['batch_size']}: "
            f"task update={only_item['loop_frequency_hz']} Hz, "
            f"task update + obs={obs_item['loop_frequency_hz']} Hz, "
            f"with-obs batch_step={obs_step_ms:.1f} ms, "
            f"with-obs env_throughput≈{obs_item['loop_frequency_hz'] * obs_item['batch_size']:.1f} env-step/s, "
            f"obs impact={slowdown:.1f}%"
        )
        lines.append(
            "- "
            f"batch_size={only_item['batch_size']} detail: "
            f"task-only batch_step={only_step_ms:.1f} ms, "
            f"with-obs batch_step={obs_step_ms:.1f} ms"
        )

    lines.append("")
    lines.append("## Env-Level Breakdown")
    for item in env_obs:
        capture_share = (
            100.0 * item["capture_observation_mean_ms"] / item["total_mean_ms"]
            if item["total_mean_ms"] > 0
            else 0.0
        )
        lines.append(
            "- "
            f"batch_size={item['batch_size']}: "
            f"capture={item['capture_observation_mean_ms']} ms, "
            f"update={item['update_mean_ms']} ms, "
            f"total={item['total_mean_ms']} ms, "
            f"capture_share={capture_share:.1f}%"
        )

    lines.append("")
    lines.append("## GPU Memory")
    for item in task_only:
        lines.append(
            "- "
            f"batch_size={item['batch_size']}: "
            f"peak_gpu_memory={item['gpu_memory_peak_mb']} MB"
        )

    analysis_path = suite_dir / "analysis.md"
    analysis_path.write_text("\n".join(lines) + "\n", encoding="utf-8")


def percentage_delta(new_value: float, baseline: float) -> float:
    if baseline == 0:
        return 0.0
    return (new_value - baseline) / baseline * 100.0


if __name__ == "__main__":
    raise SystemExit(main())
